"use client";

import { useState } from "react";
import {
  Sidebar,
  SidebarProvider,
  SidebarHeader,
  SidebarContent,
  SidebarFooter,
  SidebarMenu,
  SidebarMenuItem,
} from "@/components/ui/sidebar";

const EASE = "cubic-bezier(0.165,0.85,0.45,1)";
const DURATION = 300;
const EXPANDED = "18rem";
const COLLAPSED = "3.3rem";

const recents = [
  "Vinyl record collection organization",
  "Sourdough starter troubleshooting",
  "Plant care for low-light apartments",
  "Travel itinerary for Kyoto in spring",
  "Learning watercolor techniques",
  "Building a custom mechanical keyboard",
];

const starred = ["Designing a cozy reading nook"];

type NavItem = {
  label: string;
  icon: React.ReactNode;
  shortcut?: string;
};

export default function ClaudeSidebar() {
  const [active, setActive] = useState("New chat");
  const [collapsed, setCollapsed] = useState(false);

  const navItems: NavItem[] = [
    { label: "New chat", icon: <PlusIcon />, shortcut: "Ctrl+⇧+O" },
    { label: "Search", icon: <SearchIcon />, shortcut: "Ctrl+K" },
    { label: "Chats", icon: <ChatsIcon /> },
    { label: "Projects", icon: <ProjectsIcon /> },
    { label: "Code", icon: <CodeIcon /> },
    { label: "Customize", icon: <CustomizeIcon /> },
    { label: "Design", icon: <DesignIcon /> },
  ];

  return (
    <div className="relative flex h-full min-h-[520px]">
      <SidebarProvider
        defaultOpen
        className="min-h-0! h-full w-fit"
        style={{ "--sidebar-width": EXPANDED } as React.CSSProperties}
      >
        {/* Width-animated wrapper. Inner Sidebar is w-full so it follows the wrapper. */}
        <div
          className="shrink-0 overflow-hidden"
          style={{
            width: collapsed ? COLLAPSED : EXPANDED,
            transition: `width ${DURATION}ms ${EASE}`,
          }}
        >
          <Sidebar
            collapsible="none"
            className="flex h-full min-h-[520px] w-full! flex-col bg-sidebar text-sidebar-foreground border-r border-sidebar-border"
            style={{ transition: `background-color 35ms ${EASE}` }}
          >
            {/* Header — wordmark fades out, toggle pinned top-right */}
            <SidebarHeader className="relative flex-row! w-full items-center gap-0! p-2! pt-2 h-12 shrink-0">
              <div
                className="flex items-center gap-1.5 pl-2 h-8 overflow-clip"
                style={{
                  transition: `opacity 150ms ${EASE}`,
                  opacity: collapsed ? 0 : 1,
                  pointerEvents: collapsed ? "none" : "auto",
                }}
              >
                <ClaudeWordmark />
              </div>
              <button
                type="button"
                aria-label={collapsed ? "Open sidebar" : "Close sidebar"}
                title={collapsed ? "Open sidebar" : "Close sidebar"}
                onClick={() => setCollapsed((c) => !c)}
                className="absolute right-2 top-2 z-10 grid size-8 cursor-pointer place-items-center rounded-md text-muted-foreground transition-colors duration-150 hover:bg-sidebar-accent hover:text-sidebar-accent-foreground"
              >
                <PanelIcon />
              </button>
            </SidebarHeader>

            {/* Primary nav */}
            <SidebarMenu className="gap-px! pt-2 px-2">
              {navItems.map((it) => (
                <SidebarMenuItem key={it.label} className="list-none!">
                  <NavRow
                    item={it}
                    active={active === it.label}
                    collapsed={collapsed}
                    onClick={() => setActive(it.label)}
                  />
                </SidebarMenuItem>
              ))}
              {/* "More" caret */}
              <SidebarMenuItem className="list-none!">
                <button
                  aria-label="More"
                  className="group flex h-9 w-full items-center rounded-lg px-4 text-sm text-muted-foreground transition-colors duration-75 hover:bg-sidebar-accent hover:text-sidebar-accent-foreground overflow-hidden"
                >
                  <div className="flex w-full -translate-x-2 items-center gap-3">
                    <span className="grid size-5 shrink-0 place-items-center opacity-60">
                      <ChevronDownIcon />
                    </span>
                    <span
                      className="flex-1 truncate text-left"
                      style={{
                        transition: `opacity 150ms ${EASE}`,
                        opacity: collapsed ? 0 : 1,
                      }}
                    >
                      More
                    </span>
                  </div>
                </button>
              </SidebarMenuItem>
            </SidebarMenu>

            {/* Lists — fully fade out + inert when collapsed */}
            <SidebarContent
              className="gap-0! pt-2 overflow-x-hidden!"
              style={{
                transition: `opacity 150ms ${EASE}`,
                opacity: collapsed ? 0 : 1,
                pointerEvents: collapsed ? "none" : "auto",
              }}
              aria-hidden={collapsed}
              inert={collapsed ? ("" as unknown as boolean) : undefined}
            >
              <div className="px-2 mt-2">
                <Section title="Starred">
                  {starred.map((t) => (
                    <ChatRow key={t} title={t} />
                  ))}
                </Section>
                <Section title="Recents">
                  {recents.map((t) => (
                    <ChatRow key={t} title={t} />
                  ))}
                </Section>
              </div>
            </SidebarContent>

            {/* User card */}
            <SidebarFooter className="p-0! gap-0! border-t border-sidebar-border mt-auto">
              <button
                className="group flex h-16 w-full items-center gap-3 px-2 transition-colors duration-150 hover:bg-sidebar-accent/50 overflow-hidden"
                aria-label="User menu"
              >
                <div className="flex w-full items-center gap-3">
                  <div className="grid size-9 shrink-0 place-items-center rounded-full bg-sidebar-primary text-sm font-semibold text-sidebar-primary-foreground">
                    N
                  </div>
                  <div
                    className="flex flex-1 flex-col items-start min-w-0"
                    style={{
                      transition: `opacity 150ms ${EASE}`,
                      opacity: collapsed ? 0 : 1,
                    }}
                  >
                    <span className="truncate text-sm font-medium">
                      Nova Park
                    </span>
                    <span className="truncate text-[11px] text-muted-foreground">
                      Pro plan
                    </span>
                  </div>
                  <span
                    className="grid size-7 place-items-center rounded-md text-muted-foreground transition-colors duration-150 group-hover:bg-sidebar-accent group-hover:text-sidebar-accent-foreground"
                    style={{
                      transition: `opacity 150ms ${EASE}`,
                      opacity: collapsed ? 0 : 1,
                    }}
                  >
                    <DownloadIcon />
                  </span>
                </div>
              </button>
            </SidebarFooter>
          </Sidebar>
        </div>
      </SidebarProvider>
    </div>
  );
}

function NavRow({
  item,
  active,
  collapsed,
  onClick,
}: {
  item: NavItem;
  active: boolean;
  collapsed: boolean;
  onClick: () => void;
}) {
  return (
    <button
      onClick={onClick}
      aria-label={item.label}
      title={collapsed ? item.label : undefined}
      className={`group relative flex h-9 w-full items-center rounded-lg px-4 text-sm transition-colors duration-75 active:scale-[0.99] overflow-hidden ${
        active
          ? "bg-sidebar-accent text-sidebar-accent-foreground"
          : "text-sidebar-foreground/80 hover:bg-sidebar-accent/60 hover:text-sidebar-accent-foreground"
      }`}
    >
      <div className="flex w-full -translate-x-2 items-center gap-3">
        <span className="grid size-5 shrink-0 place-items-center text-sidebar-foreground">
          {item.icon}
        </span>
        <span
          className="flex-1 truncate text-left"
          style={{
            transition: `opacity 150ms ${EASE}`,
            opacity: collapsed ? 0 : 1,
          }}
        >
          {item.label}
        </span>
        {item.shortcut && (
          <span
            className="text-[11px] text-muted-foreground opacity-0 transition-opacity duration-75 group-hover:opacity-100"
            style={{ display: collapsed ? "none" : undefined }}
          >
            {item.shortcut}
          </span>
        )}
      </div>
    </button>
  );
}

function Section({
  title,
  children,
}: {
  title: string;
  children: React.ReactNode;
}) {
  return (
    <div className="mb-4">
      <h3 className="px-2 pb-1 text-[11px] font-medium tracking-wide text-muted-foreground select-none">
        {title}
      </h3>
      <ul className="flex flex-col gap-px">{children}</ul>
    </div>
  );
}

function ChatRow({ title }: { title: string }) {
  return (
    <li>
      <a
        href="#"
        className="group relative flex h-8 items-center rounded-lg px-3 text-[13px] text-sidebar-foreground/80 transition-colors duration-75 hover:bg-sidebar-accent/60 hover:text-sidebar-accent-foreground"
      >
        <span className="flex-1 truncate group-hover:mask-[linear-gradient(to_right,black_78%,transparent_95%)]">
          {title}
        </span>
        <span className="absolute right-1 top-1/2 -translate-y-1/2 grid size-7 place-items-center rounded-md text-muted-foreground opacity-0 transition-opacity duration-150 group-hover:opacity-100 hover:bg-sidebar-accent">
          <DotsIcon />
        </span>
      </a>
    </li>
  );
}

/* ───────────────────── Icons (with hover micro-animations) ───────────────────── */

function PlusIcon() {
  return (
    <span className="inline-flex size-5 items-center justify-center rounded-full bg-sidebar-foreground/10 transition-transform duration-200 ease-out group-hover:-rotate-3 group-hover:scale-110 group-active:rotate-6 group-active:scale-95">
      <svg width="12" height="12" viewBox="0 0 20 20" fill="currentColor">
        <path d="M10 3a.75.75 0 0 1 .75.75v5.5h5.5a.75.75 0 0 1 0 1.5h-5.5v5.5a.75.75 0 0 1-1.5 0v-5.5h-5.5a.75.75 0 0 1 0-1.5h5.5v-5.5A.75.75 0 0 1 10 3" />
      </svg>
    </span>
  );
}

function SearchIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
      <path d="M8.5 2a6.5 6.5 0 0 1 4.935 10.728l4.419 4.419a.5.5 0 0 1-.707.707l-4.42-4.419A6.5 6.5 0 1 1 8.5 2m0 1a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11" />
    </svg>
  );
}

function ChatsIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
      <path
        className="transition-transform duration-200 ease-out group-hover:-translate-x-[0.5px]"
        d="M8.99962 2C12.3133 2 14.9996 4.68629 14.9996 8C14.9996 11.3137 12.3133 14 8.99962 14H2.49962C2.30105 13.9998 2.12113 13.8821 2.04161 13.7002C1.96224 13.5181 1.99835 13.3058 2.1334 13.1602L3.93516 11.2178C3.34317 10.2878 2.99962 9.18343 2.99962 8C2.99962 4.68643 5.68609 2.00022 8.99962 2ZM8.99962 3C6.23838 3.00022 3.99961 5.23871 3.99961 8C3.99961 9.11212 4.36265 10.1386 4.97618 10.9688C5.11884 11.1621 5.1035 11.4293 4.94004 11.6055L3.64512 13H8.99962C11.761 13 13.9996 10.7614 13.9996 8C13.9996 5.23858 11.761 3 8.99962 3Z"
      />
      <path
        className="transition-transform duration-200 ease-out group-hover:translate-x-[0.5px]"
        d="M16.5445 9.72754C16.4182 9.53266 16.1678 9.44648 15.943 9.53418C15.7183 9.62215 15.5932 9.85502 15.6324 10.084L15.7369 10.3955C15.9073 10.8986 16.0006 11.438 16.0006 12C16.0006 13.1123 15.6376 14.1386 15.024 14.9687C14.8811 15.1621 14.8956 15.4302 15.0592 15.6064L16.3531 17H11.0006C9.54519 17 8.23527 16.3782 7.32091 15.3848L7.07091 15.1103C6.88996 14.9645 6.62535 14.9606 6.43907 15.1143C6.25267 15.2682 6.20668 15.529 6.31603 15.7344L6.58458 16.0625C7.68048 17.253 9.25377 18 11.0006 18H17.5006C17.6991 17.9998 17.8791 17.8822 17.9586 17.7002C18.038 17.5181 18.0018 17.3058 17.8668 17.1602L16.0631 15.2178C16.6554 14.2876 17.0006 13.1837 17.0006 12C17.0006 11.3271 16.8891 10.6792 16.6842 10.0742L16.5445 9.72754Z"
      />
    </svg>
  );
}

function ProjectsIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
      <path
        className="origin-center transition-transform duration-200 ease-out group-hover:scale-95"
        d="M15.8198 7C16.6885 7.00025 17.3624 7.73158 17.3178 8.57617L17.2993 8.74707L16.1332 15.7471C16.0126 16.4699 15.3865 16.9996 14.6538 17H5.34711C4.6142 16.9998 3.98833 16.47 3.86762 15.7471L2.7016 8.74707C2.54922 7.83277 3.25418 7 4.18109 7H15.8198ZM4.18109 8C3.87216 8 3.63722 8.27731 3.68793 8.58203L4.85394 15.582C4.89413 15.8229 5.10291 15.9998 5.34711 16H14.6538C14.8978 15.9996 15.1068 15.8228 15.1469 15.582L16.3129 8.58203L16.3188 8.46973C16.3036 8.21259 16.0899 8.00023 15.8198 8H4.18109Z"
      />
      <path
        className="transition-transform duration-200 ease-out group-hover:-translate-y-[1.4px] group-hover:translate-x-[0.5px] group-hover:rotate-3"
        d="M16.0004 5.5C16.0004 5.224 15.7764 5.00024 15.5004 5H4.50043C4.22428 5 4.00043 5.22386 4.00043 5.5C4.00043 5.77614 4.22428 6 4.50043 6H15.5004C15.7764 5.99976 16.0004 5.776 16.0004 5.5Z"
      />
      <path
        className="transition-transform duration-200 ease-out group-hover:-translate-y-[2.8px] group-hover:translate-x-px group-hover:rotate-6"
        d="M14.5004 3.5C14.5004 3.224 14.2764 3.00024 14.0004 3H6.00043C5.72428 3 5.50043 3.22386 5.50043 3.5C5.50043 3.77614 5.72428 4 6.00043 4H14.0004C14.2764 3.99976 14.5004 3.776 14.5004 3.5Z"
      />
    </svg>
  );
}

function CodeIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
      <path d="M11.6318 4.01757C11.898 4.09032 12.055 4.36555 11.9824 4.63183L8.98242 15.6318C8.90966 15.8981 8.63449 16.0551 8.36816 15.9824C8.10193 15.9097 7.94495 15.6345 8.01758 15.3682L11.0176 4.36816C11.0904 4.102 11.3656 3.94497 11.6318 4.01757Z" />
      <path
        className="transition-transform duration-200 ease-out group-hover:translate-x-[1px]"
        d="M13.124 6.17089C13.3059 5.96325 13.6213 5.9423 13.8291 6.12402L17.8291 9.62402C17.9375 9.7295 18 9.86641 18 10.0001C18 10.1442 17.9375 10.281 17.8291 10.376L13.8291 13.876C13.5449 14.0498 13.2833 14.011 13.124 13.8291C12.9649 13.6472 12.9842 13.3927 13.1709 13.124L16.7412 10L13.1709 6.87597C12.9632 6.69411 12.9422 6.37866 13.124 6.17089Z"
      />
      <path
        className="transition-transform duration-200 ease-out group-hover:-translate-x-[1px]"
        d="M6.25293 6.06542C6.45509 5.95025 6.71675 5.98908 6.87598 6.17089C7.03513 6.35279 7.03933 6.6176 6.89844 6.80273L6.8291 6.87597L3.25879 10L6.8291 13.124C7.03682 13.3059 7.05771 13.6213 6.87598 13.8291C6.69413 14.0369 6.37869 14.0578 6.1709 13.876L2.1709 10.376C2.06247 10.281 2 10.1441 2 10C2.00005 9.85591 2.06247 9.71893 2.1709 9.62402L6.1709 6.12402L6.25293 6.06542Z"
      />
    </svg>
  );
}

function CustomizeIcon() {
  return (
    <span className="inline-flex transition-transform duration-200 ease-out group-hover:-rotate-3 group-hover:scale-110 group-active:rotate-6 group-active:scale-95">
      <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
        <path d="M12.5 3A1.5 1.5 0 0 1 14 4.5V6h.5A3.5 3.5 0 0 1 18 9.5v6a1.5 1.5 0 0 1-1.5 1.5h-13a1.5 1.5 0 0 1-1.492-1.347L2 15.5v-6A3.5 3.5 0 0 1 5.5 6H6V4.5A1.5 1.5 0 0 1 7.5 3zM3 15.5l.01.1a.5.5 0 0 0 .49.4h13a.5.5 0 0 0 .5-.5V12h-4v.5a.5.5 0 0 1-1 0V12H8v.5a.5.5 0 0 1-1 0V12H3zM5.5 7A2.5 2.5 0 0 0 3 9.5V11h4v-.5a.5.5 0 0 1 1 0v.5h4v-.5a.5.5 0 0 1 1 0v.5h4V9.5A2.5 2.5 0 0 0 14.5 7zm2-3a.5.5 0 0 0-.5.5V6h6V4.5a.5.5 0 0 0-.5-.5z" />
      </svg>
    </span>
  );
}

function DesignIcon() {
  return (
    <span className="inline-flex transition-transform duration-200 ease-out group-hover:-rotate-3 group-hover:scale-110 group-active:rotate-6 group-active:scale-95">
      <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
        <path d="M6 10a1 1 0 1 1 0 2 1 1 0 0 1 0-2m8-2a1 1 0 1 1 0 2 1 1 0 0 1 0-2M7 6a1 1 0 1 1 0 2 1 1 0 0 1 0-2m4-1a1 1 0 1 1 0 2 1 1 0 0 1 0-2" />
        <path
          fillRule="evenodd"
          d="M10 2.5a7.5 7.5 0 0 1 7.5 7.5c0 1.099-.321 1.874-.929 2.363-.581.469-1.335.599-2.028.63-.674.03-1.462-.034-2.026-.04-.375-.004-.9-.036-1.221.2-.213.157-.339.426-.402.865-.07.486-.05.98-.082 1.47-.031.477-.11 1.082-.507 1.493-.763.788-2.095.366-2.984.025A7.5 7.5 0 0 1 10 2.5m0 1a6.5 6.5 0 0 0-2.321 12.572c.448.172 1.51.624 1.907.214.117-.121.196-.374.227-.863.034-.516.016-1.035.09-1.548.078-.534.264-1.134.801-1.528.515-.378 1.211-.4 1.824-.394.69.008 1.316.07 1.97.041.633-.029 1.119-.146 1.445-.409.301-.242.557-.684.557-1.585A6.5 6.5 0 0 0 10 3.5"
          clipRule="evenodd"
        />
      </svg>
    </span>
  );
}

function PanelIcon() {
  return (
    <svg width="18" height="18" viewBox="0 0 20 20" fill="currentColor">
      <path d="M16.5 4A1.5 1.5 0 0 1 18 5.5v9a1.5 1.5 0 0 1-1.5 1.5h-13A1.5 1.5 0 0 1 2 14.5v-9A1.5 1.5 0 0 1 3.5 4zM7 15h9.5a.5.5 0 0 0 .5-.5v-9a.5.5 0 0 0-.5-.5H7zM3.5 5a.5.5 0 0 0-.5.5v9a.5.5 0 0 0 .5.5H6V5z" />
    </svg>
  );
}

function ChevronDownIcon() {
  return (
    <svg width="14" height="14" viewBox="0 0 256 256" fill="currentColor">
      <path d="M213.66,101.66l-80,80a8,8,0,0,1-11.32,0l-80-80A8,8,0,0,1,53.66,90.34L128,164.69l74.34-74.35a8,8,0,0,1,11.32,11.32Z" />
    </svg>
  );
}

function DotsIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 20 20" fill="currentColor">
      <path d="M4.5 8.5a1.5 1.5 0 1 1 0 3 1.5 1.5 0 0 1 0-3m5.5 0a1.5 1.5 0 1 1 0 3 1.5 1.5 0 0 1 0-3m5.5 0a1.5 1.5 0 1 1 0 3 1.5 1.5 0 0 1 0-3" />
    </svg>
  );
}

function DownloadIcon() {
  return (
    <svg width="14" height="14" viewBox="0 0 20 20" fill="currentColor">
      <path d="M10 3a.5.5 0 0 1 .5.5v8.79l2.65-2.64a.5.5 0 0 1 .7.7l-3.5 3.5a.5.5 0 0 1-.7 0l-3.5-3.5a.5.5 0 0 1 .7-.7l2.65 2.64V3.5A.5.5 0 0 1 10 3M4 15.5a.5.5 0 0 1 .5-.5h11a.5.5 0 0 1 0 1h-11a.5.5 0 0 1-.5-.5" />
    </svg>
  );
}

function ClaudeWordmark() {
  return (
    <svg
      viewBox="0 0 68 16"
      className="h-4 text-sidebar-foreground"
      height="16"
      fill="currentColor"
